import { useEffect, useState } from "react";

export default function AfterHero() {
  const [stats, setStats] = useState({
    lost: 0,
    found: 0,
    returned: 0,
  });
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    const fetchstats = async () => {
      try {
        const res = await fetch("http://localhost:5000/item/stats");
        const newData = await res.json();
        setStats(newData.data);
        setLoading(false);
      } catch (err) {
        console.error(err);
      }
    };
    fetchstats();
  }, []);
  return (
    <section className="bg-blue-100 w-full flex justify-center py-20 px-5">
      <div className="bg-white rounded-2xl border-2 border-orange shadow-2xl p-10 flex flex-wrap justify-center gap-10">
        {/* Lost Items Card */}
        <div className="flex flex-col items-center bg-red-100 rounded-xl p-6 shadow-lg transform transition-all duration-300 hover:scale-105 hover:shadow-2xl">
          <img className="w-20 h-20 mb-4" src="/lost.png" alt="Lost Items" />
          <h2 className="text-xl font-semibold text-red-700 text-center">
            {loading ? "Loading..." : `${stats.lost}+ Lost Items Issued`}
          </h2>
        </div>

        {/* Found Items Card */}
        <div className="flex flex-col items-center bg-green-100 rounded-xl p-6 shadow-lg transform transition-all duration-300 hover:scale-105 hover:shadow-2xl">
          <img className="w-20 h-20 mb-4" src="/found.png" alt="Found Items" />
          <h2 className="text-xl font-semibold text-green-700 text-center">
            {loading ? "Loading..." : `${stats.found}+ found Items Issued`}
          </h2>
        </div>

        {/* Returned Items Card */}
        <div className="flex flex-col items-center bg-yellow-100 rounded-xl p-6 shadow-lg transform transition-all duration-300 hover:scale-105 hover:shadow-2xl">
          <img
            className="w-20 h-20 mb-4"
            src="/return.png"
            alt="Returned Items"
          />
          <h2 className="text-xl font-semibold text-yellow-700 text-center">
            {loading ? "Loading..." : `${stats.returned}+ Items returned`}
          </h2>
        </div>
      </div>
    </section>
  );
}
